<!DOCTYPE html>
<html lang="fa" dir="rtl">
<head>
<meta charset="UTF-8">
<style>
  @import url('https://fonts.googleapis.com/css2?family=Vazirmatn:wght@300;400;500;600;700;800&family=Space+Grotesk:wght@400;500;600;700&display=swap');

  @page { margin: 10mm 12mm 10mm 12mm; }

  :root {
    --green:   #8BC74A;
    --black:   #0F0F0F;
    --ink:     #1C1C1C;
    --subtle:  #6B6B6B;
    --line:    #D8D8D8;
    --bg-soft: #F4F4F4;
    --white:   #FFFFFF;
  }

  html { font-size: 8.5px; }
  * { box-sizing: border-box; margin: 0; padding: 0; }

  body {
    font-family: 'Vazirmatn', Tahoma, sans-serif;
    font-size: 1rem;
    color: var(--ink);
    direction: rtl;
    background: var(--white);
    width: 100%;
    -webkit-print-color-adjust: exact;
    print-color-adjust: exact;
  }

  /* ─── HEADER ─── */
  .header {
    width: 100%;
    border-bottom: 3px solid var(--green);
    padding-bottom: 0.8em;
    margin-bottom: 1em;
    /* use table layout for safe RTL two-column */
    display: table;
  }

  .header-right {
    display: table-cell;
    vertical-align: top;
    text-align: right;
    width: 55%;
  }

  .header-left {
    display: table-cell;
    vertical-align: top;
    text-align: left;
    direction: ltr;
    width: 45%;
  }

  .brand-fa {
    font-size: 1.6rem;
    font-weight: 800;
    color: var(--black);
    line-height: 1;
  }

  .brand-en {
    font-family: 'Space Grotesk', sans-serif;
    font-size: 0.82rem;
    font-weight: 600;
    color: var(--green);
    letter-spacing: 0.08em;
    margin-top: 0.1em;
  }

  .brand-addr {
    font-size: 0.8rem;
    color: var(--subtle);
    margin-top: 0.45em;
    line-height: 1.7;
    direction: rtl;
    text-align: right;
  }

  .doc-type-label {
    font-size: 1.8rem;
    font-weight: 800;
    color: var(--black);
    line-height: 1;
    text-align: right;
    direction: rtl;
  }

  .doc-type-label em {
    font-style: normal;
    color: var(--green);
  }

  .doc-meta-table {
    margin-top: 0.6em;
    border-collapse: collapse;
    direction: rtl;
    float: right;
    clear: both;
  }

  .doc-meta-table td {
    padding: 0.12em 0.4em 0.12em 0;
    font-size: 0.82rem;
    vertical-align: middle;
    border: none;
    background: transparent;
  }

  .dml { color: var(--subtle); font-weight: 600; text-align: right; }
  .dmv {
    font-family: 'Space Grotesk', sans-serif;
    font-weight: 600;
    color: var(--ink);
    direction: ltr;
    text-align: left;
  }

  /* ─── INFO CARDS ─── */
  .info-grid {
