<!-- ════ HEADER ════ -->
<div class="header">
  <div class="header-right">
    <div class="brand-fa">هوشمندسازی نویان</div>
    <div class="brand-en">NOYAN SMART SOLUTIONS</div>
    <div class="brand-addr">
      نیاوران، سه‌راه یاسر، جنب بانک پاسارگاد، پلاک ۲۳۴ واحد ۱۰۴<br>
      تلفن: ۰۹۱۹۸۲۵۷۰۰۹
    </div>
  </div>
  <div class="header-left">
    <div class="doc-type-label" style="text-align:right; direction:rtl;">سفارش <em>فروش</em></div>
    <table class="doc-meta-table">
      <tr>
        <td class="dml">شماره :</td>
        <td class="dmv">{{ doc.name }}</td>
      </tr>
      <tr>
        <td class="dml">تاریخ :</td>
        <td class="dmv">{{ doc.get_formatted("transaction_date") }}</td>
      </tr>
      <tr>
        <td class="dml">تاریخ تحویل :</td>
        <td class="dmv">{{ doc.get_formatted("delivery_date") if doc.delivery_date else "—" }}</td>
      </tr>
      {% if doc.po_no %}
      <tr>
        <td class="dml">شماره سفارش خریدار :</td>
        <td class="dmv">{{ doc.po_no }}</td>
      </tr>
      {% endif %}
    </table>
  </div>
</div>

<!-- ════ INFO CARDS ════ -->
<div class="info-grid">
  <div class="info-card">
    <div class="card-head">فروشنده</div>
    <div class="card-body">
      <div class="crow"><span class="clabel">نام :</span><span class="cval">{{ doc.company }}</span></div>
      <div class="crow"><span class="clabel">شناسه اقتصادی :</span><span class="cval">{{ doc.company_tax_id or "" }}</span></div>
      <div class="crow"><span class="clabel">شماره ملی :</span><span class="cval"></span></div>
      <div class="crow"><span class="clabel">فکس :</span><span class="cval"></span></div>
    </div>
  </div>
  <div class="info-card">
    <div class="card-head">خریدار</div>
    <div class="card-body">
      <div class="crow"><span class="clabel">نام :</span><span class="cval">{{ doc.customer_name }}</span></div>
      <div class="crow"><span class="clabel">شناسه اقتصادی :</span><span class="cval">{{ doc.tax_id or "" }}</span></div>
      <div class="crow"><span class="clabel">نشانی صورتحساب :</span><span class="cval">{{ doc.customer_address or "" }}</span></div>
      <div class="crow"><span class="clabel">نشانی تحویل :</span><span class="cval">{{ doc.shipping_address or doc.customer_address or "" }}</span></div>
      <div class="crow"><span class="clabel">تلفن :</span><span class="cval">{{ doc.contact_mobile or doc.contact_phone or "" }}</span></div>
    </div>
  </div>
</div>

<!-- ════ ITEMS ════ -->
<div class="sec-label">مشخصات کالا یا خدمات</div>
<table class="items">
  <colgroup>
    <col style="width:3%">
    <col style="width:8%">
    <col style="width:35%">
    <col style="width:6%">
    <col style="width:6%">
    <col style="width:13%">
    <col style="width:11%">
    <col style="width:18%">
  </colgroup>
  <thead>
    <tr>
      <th>#</th>
      <th>کد کالا</th>
      <th class="h-desc">شرح کالا / خدمت</th>
      <th>تعداد</th>
      <th>واحد</th>
      <th>مبلغ واحد</th>
      <th>تخفیف</th>
      <th>مبلغ کل</th>
    </tr>
  </thead>
  <tbody>
    {% for item in doc.items %}
    <tr>
      <td class="idx">{{ loop.index }}</td>
      <td class="code">{{ item.item_code }}</td>
      <td class="r">{{ item.item_name }}{% if item.custom_item_name_persian and item.custom_item_name_persian != item.item_name %}<br><span style="font-size:0.76rem;color:#6B6B6B;">{{ item.custom_item_name_persian }}</span>{% endif %}</td>
      <td class="c">{{ item.qty | int }}</td>
      <td class="c">{{ item.uom }}</td>
      <td class="num">{{ "{:,.2f}".format(item.price_list_rate or item.rate) }}</td>
      <td class="disc">{% if item.discount_percentage %}{{ "{:.1f}".format(item.discount_percentage) }}%{% elif item.discount_amount %}{{ "{:,.2f}".format(item.discount_amount) }}{% else %}—{% endif %}</td>
      <td class="num" style="font-weight:700;">{{ "{:,.2f}".format(item.amount) }}</td>
    </tr>
    {% endfor %}
    {% set empty_rows = [6 - doc.items|length, 0]|max %}
    {% for i in range(empty_rows) %}
    <tr class="empty"><td></td><td></td><td></td><td></td><td></td><td></td><td></td><td></td></tr>
    {% endfor %}
  </tbody>
</table>

<!-- ════ BOTTOM ════ -->
<div class="bottom">
  <div class="bottom-left">
    <!--<div class="words-box">-->
    <!--  <div class="wlabel">مبلغ به حروف</div>-->
    <!--  <div class="wval">{{ doc.custom_in_words_fa or "" }}</div>-->
    <!--</div>-->
    <div class="pay-box">
      <div class="pay-row">
        <span class="pay-lbl">نوع پرداخت :</span>
        <span class="pay-val">
          <span class="chk-pair">
            <span class="chk-item"><span class="chk"></span> نقدی</span>
            <span class="chk-item"><span class="chk"></span> غیرنقدی</span>
          </span>
        </span>
      </div>
      <div class="pay-row">
        <span class="pay-lbl">شرایط :</span>
        <span class="pay-val">{{ doc.payment_terms_template or "—" }}</span>
      </div>
    </div>
  </div>
  <div class="bottom-right">
    <div class="totals-box">
      <div class="trow">
        <span class="tlbl">جمع کل</span>
        <span class="tval">{{ "{:,.2f}".format(doc.total) }} {{ doc.currency }}</span>
      </div>
      <div class="trow">
        <span class="tlbl">اضافات</span>
        <span class="tval">—</span>
      </div>
      <div class="trow">
        <span class="tlbl">تخفیف{% if doc.additional_discount_percentage %} ({{ doc.additional_discount_percentage }}%) {% else %}{% endif%}</span>
        <span class="tval">{% if doc.discount_amount %}{{ "{:,.2f}".format(doc.discount_amount) }} {{ doc.currency }}{% else %}—{% endif %}</span>
      </div>
      <div class="trow">
        <span class="tlbl">مالیات و عوارض</span>
        <span class="tval">{% if doc.total_taxes_and_charges and doc.total_taxes_and_charges > 0 %}{{ "{:,.2f}".format(doc.total_taxes_and_charges) }} {{ doc.currency }}{% else %}—{% endif %}</span>
      </div>
      <div class="trow grand">
        <span class="tlbl">مبلغ قابل پرداخت</span>
        <span class="tval">{{ "{:,.2f}".format(doc.grand_total) }} {{ doc.currency }}</span>
      </div>
    </div>
  </div>
</div>

<!-- ════ BANK ════ -->
<div class="bank-box">
  <div class="bhead">اطلاعات حساب بانکی</div>
  <div class="bbody">
    <span class="blbl">شماره شبا : </span><div class="bval">IR140560086780018902790001</div>
    &nbsp;&nbsp;&nbsp;
    <span class="blbl">شماره کارت (فرناز عسکری - نوید پاینده ) :</span><div class="bval">6219-8610-9160-4156</div>
    &nbsp;&nbsp;&nbsp;
    <span class="blbl">شماره حساب بانک سامان : </span><div class="bval">867-800-18902790-1</div>
    {% if doc.terms %}<br><span style="font-size:0.78rem;color:#6B6B6B;">{{ doc.terms }}</span>{% endif %}
  </div>
</div>

<!-- ════ SIGNATURE ════ -->
<div class="sig-grid">
  <div class="sig-cell">مهر و امضاء فروشنده (تایید سفارش)</div>
  <div class="sig-cell">مهر و امضاء خریدار (تایید نهایی)</div>
</div>

<!-- ════ FOOTER ════ -->
<div class="footer">
  <div class="footer-l"><span>NOYAN</span> · smartnoyan.com</div>
</div>

</body>
</html>

