    <table class="doc-meta-table">
      <tr>
        <td class="dml">شماره فاکتور :</td>
        <td class="dmv">{{ doc.name }}</td>
      </tr>
      <tr>
        <td class="dml">تاریخ صدور :</td>
        <td class="dmv">{{ doc.get_formatted("posting_date") }}</td>
      </tr>
      <tr>
        <td class="dml">سررسید پرداخت :</td>
        <td class="dmv">{{ doc.get_formatted("due_date") if doc.due_date else "—" }}</td>
      </tr>
      {% if doc.po_no %}
      <tr>
        <td class="dml">شماره سفارش خریدار :</td>
        <td class="dmv">{{ doc.po_no }}</td>
      </tr>
      {% endif %}
    </table>
  </div>
</div>

<!-- ════ INFO CARDS ════ -->
<div class="info-grid">
  <div class="info-card">
    <div class="card-head">فروشنده</div>
