      </div>
      <div class="pay-row">
        <span class="pay-lbl">مبلغ پرداختی :</span>
        <span class="pay-val">{{ "{:,.2f}".format(doc.grand_total - (doc.outstanding_amount or 0)) }} {{ doc.currency }}</span>
      </div>
    </div>
  </div>
  <div class="bottom-right">
    <div class="totals-box">
      <div class="trow">
        <span class="tlbl">جمع کل</span>
        <span class="tval">{{ "{:,.2f}".format(doc.total) }} {{ doc.currency }}</span>
      </div>
      <div class="trow">
        <span class="tlbl">تخفیف{% if doc.additional_discount_percentage %} ({{ doc.additional_discount_percentage }}%) {% else %}{% endif%}</span>
        <span class="tval">{% if doc.discount_amount %}{{ "{:,.2f}".format(doc.discount_amount) }} {{ doc.currency }}{% else %}—{% endif %}</span>
      </div>
      <div class="trow">
        <span class="tlbl">مالیات و عوارض</span>
        <span class="tval">{% if doc.total_taxes_and_charges and doc.total_taxes_and_charges > 0 %}{{ "{:,.2f}".format(doc.total_taxes_and_charges) }} {{ doc.currency }}{% else %}—{% endif %}</span>
      </div>
      <div class="trow grand">
        <span class="tlbl">مبلغ قابل پرداخت</span>
        <span class="tval">{{ "{:,.2f}".format(doc.grand_total) }} {{ doc.currency }}</span>
      </div>
      {% if doc.outstanding_amount and doc.outstanding_amount > 0 %}
      <div class="trow due">
        <span class="tlbl">مانده بدهی</span>
        <span class="tval">{{ "{:,.2f}".format(doc.outstanding_amount) }} {{ doc.currency }}</span>
      </div>
      {% endif %}
    </div>
  </div>
</div>

<!-- ════ BANK ════ -->
<div class="bank-box">
