    &nbsp;&nbsp;&nbsp;
    <span class="blbl">شماره کارت (فرناز عسکری - نوید پاینده ) :</span><div class="bval">6219-8610-9160-4156</div>
    &nbsp;&nbsp;&nbsp;
    <span class="blbl">شماره حساب بانک سامان : </span><div class="bval">867-800-18902790-1</div>
    {% if doc.terms %}<br><span style="font-size:0.78rem;color:#6B6B6B;">{{ doc.terms }}</span>{% endif %}
  </div>
</div>

<!-- ════ SIGNATURE ════ -->
<div class="sig-grid">
  <div class="sig-cell">مهر و امضاء فروشنده</div>
  <div class="sig-cell">مهر و امضاء خریدار</div>
</div>

<!-- ════ FOOTER ════ -->
<div class="footer">
  <div class="footer-l"><span>NOYAN</span> · smartnoyan.com</div>
</div>

</body>
