  body {
    font-family: 'Vazirmatn', Tahoma, sans-serif;
    font-size: 1rem;
    color: var(--ink);
    direction: rtl;
    background: var(--white);
    width: 100%;
    -webkit-print-color-adjust: exact;
    print-color-adjust: exact;
  }

  /* ─── HEADER ─── */
  .header {
    width: 100%;
    border-bottom: 3px solid var(--green);
    padding-bottom: 0.8em;
    margin-bottom: 1em;
    display: table;
  }

  .header-right {
    display: table-cell;
    vertical-align: top;
    text-align: right;
    width: 55%;
  }

  .header-left {
    display: table-cell;
    vertical-align: top;
    text-align: left;
    direction: ltr;
    width: 45%;
  }

  .brand-fa {
    font-size: 1.6rem;
    font-weight: 800;
    color: var(--black);
