    margin-top: 0.45em;
    line-height: 1.7;
    direction: rtl;
    text-align: right;
  }

  .doc-type-label {
    font-size: 1.8rem;
    font-weight: 800;
    color: var(--black);
    line-height: 1;
    text-align: right;
    direction: rtl;
  }

  .doc-type-label em {
    font-style: normal;
    color: var(--green);
  }

  .doc-meta-table {
    margin-top: 0.6em;
    border-collapse: collapse;
    direction: rtl;
    float: right;
    clear: both;
  }

  .doc-meta-table td {
    padding: 0.12em 0.4em 0.12em 0;
    font-size: 0.82rem;
    vertical-align: middle;
    border: none;
    background: transparent;
  }

  .dml { color: var(--subtle); font-weight: 600; text-align: right; }
