  .items tbody tr { border-bottom: 1px solid var(--line); }
  .items tbody tr:nth-child(even) { background: var(--bg-soft); }

  .items tbody td {
    padding: 0.38em 0.5em;
    font-size: 0.85rem;
    border: none;
    vertical-align: middle;
  }

  .c   { text-align: center; }
  .r   { text-align: right; }
