    text-align: center;
    color: var(--subtle);
    font-size: 0.78rem;
  }

  .code {
    font-family: 'Space Grotesk', sans-serif;
    text-align: center;
    font-size: 0.75rem;
    color: var(--subtle);
    direction: ltr;
  }

  .disc {
    font-family: 'Space Grotesk', sans-serif;
    text-align: center;
    font-size: 0.78rem;
    color: var(--green);
    font-weight: 600;
    direction: ltr;
  }

  .items tbody tr.empty td { height: 1.6em; }

  /* ─── BOTTOM SECTION ─── */
  .bottom {
    width: 100%;
    display: flex;
    margin-bottom: 0.9em;
    justify-content:space-between;
    gap:0.7em
  }

  .bottom-left { display: table-cell; vertical-align: top; width: 55%; }
  .bottom-right { display: table-cell; vertical-align: top; width: 45%; }

  /* transport box */
  .pay-box {
    border: 1px solid var(--line);
    border-radius: 0.4em;
    overflow: hidden;
  }

  .pay-row {
    display: table;
    width: 100%;
    border-bottom: 1px solid var(--line);
    padding: 0.32em 0.7em;
    font-size: 0.82rem;
  }

  .pay-row:last-child { border-bottom: none; }
  .pay-lbl { display: table-cell; color: var(--subtle); font-weight: 600; width: 7em; }
  .pay-val { display: table-cell; font-weight: 500; }

  /* totals */
  .totals-box {
    border: 1px solid var(--line);
    border-radius: 0.4em;
    overflow: hidden;
  }

  .trow {
    display: table;
    width: 100%;
    border-bottom: 1px solid var(--line);
    padding: 0.32em 0.7em;
  }

  .trow:last-child { border-bottom: none; }
  .tlbl { display: table-cell; font-size: 0.8rem; font-weight: 600; color: var(--subtle); }
  .tval {
    display: table-cell;
    font-family: 'Space Grotesk', sans-serif;
    font-size: 0.85rem;
    font-weight: 600;
    text-align: left;
    direction: ltr;
    color: var(--ink);
  }

  .trow.grand { background: var(--green); }
  .trow.grand .tlbl,
  .trow.grand .tval {
    color: var(--white);
    font-weight: 800;
    font-size: 0.92rem;
  }

  .sig-grid {
    width: 100%;
    display: flex;
    justify-content:space-between;
    gap:0.7em
  }

  .sig-cell {
    display: table-cell;
    width: 50%;
    border: 1px solid var(--line);
    border-radius: 0.4em;
    height: 5em;
    text-align: center;
    vertical-align: top;
    padding-top: 0.5em;
    font-size: 0.8rem;
    font-weight: 700;
    color: var(--subtle);
  }

  /* ─── FOOTER ─── */
  .footer {
    margin-top: 0.7em;
    padding-top: 0.4em;
    border-top: 1px solid var(--line);
    display: table;
    width: 100%;
  }

  .footer-l {
    display: table-cell;
    font-size: 0.72rem;
    color: var(--subtle);
    font-family: 'Space Grotesk', sans-serif;
    direction: ltr;
    text-align: left;
  }

  .footer-l span { color: var(--green); font-weight: 700; }
</style>
</head>
